import React from 'react';
import { ToggleSmall as CarbonToggleSmall } from '@carbon/react';

const ToggleSmall = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonToggleSmall
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonToggleSmall>
    );
};

ToggleSmall.defaultProps = {
    className: ''
};

export default ToggleSmall;
